<?php namespace App\Repositories\Fee;use App\Repositories\BaseRepository;use App\Models\Fee\FeeInstallment;use Illuminate\Database\Eloquent\Collection;class FeeInstallmentRepository extends BaseRepository{    public function __construct(FeeInstallment $model)    {        $this->model = $model;        parent::__construct($model);    }    public function findByFeeStructure(int $feeStructureId): Collection    {        return $this->findByField('fee_structure_id', $feeStructureId);    }    public function getUpcomingInstallments(int $days = 30): Collection    {        return $this->query()->where('due_date', '>=', now())->where('due_date', '<=', now()->addDays($days))->orderBy('due_date', 'asc')->get();    }    public function getOverdueInstallments(): Collection    {        return $this->query()->where('due_date', '<', now())->where('status', 'pending')->get();    }    public function getByDueDateRange(string $startDate, string $endDate): Collection    {        return $this->query()->whereBetween('due_date', [$startDate, $endDate])->get();    }    public function markAsPaid(int $id): bool    {        return $this->update($id, ['status' => 'paid']);    }    public function getByAcademicYear(int $academicYearId): Collection    {        return $this->query()->whereHas('feeStructure', function ($q) use ($academicYearId) {                $q->where('academic_year_id', $academicYearId);            })->get();    }}